# The skynet benchmark as described here:
# https://github.com/atemerev/skynet
#
# Canonical (TooManyCooks) implementation:
# ../../cpp/TooManyCooks/skynet.cpp
#
# Each node forks 10 children until depthMax levels deep (10^depthMax = 100M
# leaf tasks) and sums their results. Each child is a Weave task (spawn), so
# this measures Weave's spawn/sync throughput under deep nested fan-out.
#
# The explicit {.gcsafe.} is required on Nim 2.x: gcsafety is not inferred for
# recursive procs, and the task wrapper generated by Weave's spawn demands it.

import std/[monotimes, times]
import weave
import benchutil

const depthMax = 8
const iterCount = 1

proc skynetOne(base: uint64, depth: int): uint64 {.gcsafe.} =
  if depth == depthMax:
    return base
  var offset = 1'u64
  for _ in 0 ..< (depthMax - depth - 1):
    offset *= 10

  var children: array[10, Flowvar[uint64]]
  for i in 0 ..< 10:
    children[i] = spawn skynetOne(base + offset * uint64(i), depth + 1)

  var count = 0'u64
  for i in 0 ..< 10:
    count += sync(children[i])
  result = count

proc skynet(expected: uint64) =
  let count = skynetOne(0, 0)
  if count != expected:
    echo "ERROR: wrong result - ", count

proc main() =
  let threadCount = threadCountArg(1)

  var leaves = 1'u64
  for _ in 0 ..< depthMax:
    leaves *= 10
  let expected = (leaves - 1) * leaves div 2

  echo "threads: ", threadCount

  setWeaveThreads(threadCount)
  init(Weave)

  skynet(expected) # warmup

  echo "runs:"
  let start = getMonoTime()
  for _ in 0 ..< iterCount:
    skynet(expected)
  let durUs = (getMonoTime() - start).inMicroseconds
  exit(Weave)
  echo "  - iteration_count: ", iterCount
  echo "    duration: ", durUs, " us"
  echo "    max_rss: ", peakMemoryUsageKiB(), " KiB"

when isMainModule:
  main()
